    82→    v = glm::dot(dir, qvec) * invDet;
    83→    if (v < 0.0f || u + v > 1.0f)
    84→        return false;
    85→
    86→    t = glm::dot(e2, qvec) * invDet;
    87→    return t > 0.0f;
    88→}
