    if (RayTriangleIntersection(start, dir, FRONT_V0, FRONT_V1, FRONT_V2, t_front, u_front, v_front))
        ignore = 0;

    for (size_t i = 0; i < triangles.size(); i++)
    {
        v0 = triangles[i].v0;
        v1 = triangles[i].v1;
        v2 = triangles[i].v2;

        if (ignore == 1 && light == 0)
        {
            if (i <= 9)
