    63→inline bool RayTriangleIntersection(const vec3& orig,
    64→                                    const vec3& dir,
    65→                                    const vec3& v0,
    66→                                    const vec3& v1,
    67→                                    const vec3& v2,
    68→                                    float& t,
    69→                                    float& u,
    70→                                    float& v)
    71→{
    72→    const float EPSILON = 1e-6f;
    73→    vec3 e1 = v1 - v0;
    74→    vec3 e2 = v2 - v0;
    75→    vec3 pvec = glm::cross(dir, e2);
    76→    float det = glm::dot(e1, pvec);
    77→    if (fabs(det) < EPSILON)
    78→        return false;
    79→
    80→    float invDet = 1.0f / det;
    81→    vec3 tvec = orig - v0;
    82→    u = glm::dot(tvec, pvec) * invDet;
    83→    if (u < 0.0f || u > 1.0f)
    84→        return false;
    85→
    86→    vec3 qvec = glm::cross(tvec, e1);
    87→    v = glm::dot(dir, qvec) * invDet;
    88→    if (v < 0.0f || u + v > 1.0f)
    89→        return false;
    90→
    91→    t = glm::dot(e2, qvec) * invDet;
    92→    return t > 0.0f;
    93→}
