   288→bool closest_intersection(const vec3& start, const vec3& dir, const vector<Triangle>& triangles, Intersection& cloestIntersection, Intersection& mirIntersection, int light)
   289→{
   290→
   291→    bool flag = false;
   292→    float min = 0.0;
   293→    int triangle_index, ignore = 1;
   294→    vec3 v0, v1, v2;
   295→    vec3 reflect_position, reflect_dir;
   296→    Intersection reflect_intersec;
   297→
   298→    float t_front, u_front, v_front;
   299→    if (RayTriangleIntersection(start, dir, FRONT_V0, FRONT_V1, FRONT_V2, t_front, u_front, v_front))
   300→        ignore = 0;
   301→
   302→    for (size_t i = 0; i < triangles.size(); i++)
   303→    {
   304→        v0 = triangles[i].v0;
   305→        v1 = triangles[i].v1;
   306→        v2 = triangles[i].v2;
   307→
   308→        if (ignore == 1 && light == 0)
   309→        {
   310→            if (i <= 9)
   311→            {
   312→                float t_hit, u_hit, v_hit;
   313→                if (RayTriangleIntersection(start, dir, v0, v1, v2, t_hit, u_hit, v_hit) && t_hit > 0.03f)
   314→                {
   315→                    if (!flag)
   316→                    {
   317→                        min = t_hit;
   318→                        triangle_index = i;
   319→                    }
   320→                    flag = true;
   321→                    if (min > t_hit)
   322→                    {
   323→                        min = t_hit;
   324→                        triangle_index = i;
   325→                    }
   326→                }
   327→            }
   328→        }
   329→        else if (ignore == 0 || light == 1)
   330→        {
   331→            float t_hit, u_hit, v_hit;
   332→            if (RayTriangleIntersection(start, dir, v0, v1, v2, t_hit, u_hit, v_hit) && t_hit > 0.03f)
   333→            {
   334→                if (!flag)
   335→                {
   336→                    min = t_hit;
   337→                    triangle_index = i;
   338→                }
   339→                flag = true;
   340→                if (min > t_hit)
   341→                {
   342→                    min = t_hit;
   343→                    triangle_index = i;
   344→                }
   345→            }
   346→        }
   347→    }
   348→
   349→    if (flag)
   350→    {
   351→        cloestIntersection.position = start + min * dir;
   352→        cloestIntersection.distance = min;
   353→        cloestIntersection.triangle_index = triangle_index;
   354→        if (triangle_index == 4 || triangle_index == 5)
   355→        {
   356→            reflect_position = start + min * dir;
   357→            reflect_dir = vec3(-dir[0], dir[1], dir[2]);
   358→            if (mirror_intersection(reflect_position, reflect_dir, triangles, reflect_intersec))
   359→            {
   360→                cloestIntersection.colour = reflect_intersec.colour;
   361→
   362→                mirIntersection.triangle_index = reflect_intersec.triangle_index;
   363→                mirIntersection.position = reflect_intersec.position;
   364→                mirIntersection.distance = reflect_intersec.distance;
   365→            }
   366→            cloestIntersection.is_mirror = true;
   367→        }
   368→        else
   369→        {
   370→            mirIntersection.triangle_index = triangle_index;
   371→            mirIntersection.position = start + min * dir;
   372→            mirIntersection.distance = min;
   373→            cloestIntersection.colour = triangles[triangle_index].color;
   374→            cloestIntersection.is_mirror = false;
   375→        }
   376→        return true;
   377→    }
   378→    else
   379→        return false;
   380→}
