   237→// ---------------------------------------------------------------------------
   238→// direct_light_gpu
   239→// ---------------------------------------------------------------------------
   240→inline float3 direct_light_gpu(GPUIntersection        point,
   241→                                constant GPUTriangle*  triangles,
   242→                                int                    triangle_count,
   243→                                constant RenderUniforms& uni,
   244→                                thread uint&           seed)
   245→{
   246→    int    idx           = point.triangle_index;
   247→    float3 surface_light = uni.light_pos.xyz - point.position;
   248→    float  r             = length(surface_light);
   249→
   250→    float  result_dot    = dot(surface_light, triangles[idx].normal.xyz);
   251→    float  area_divisor  = 4.0f * M_PI_F * r * r;
   252→
   253→    float3 light_area;
   254→    if (result_dot > 0.0f) {
   255→        light_area = (result_dot / area_divisor) * uni.light_colour.xyz;
   256→    } else {
   257→        light_area = float3(0.0f);
   258→    }
   259→
   260→    // --- Shadow branch ---
   261→    bool do_shadow_check = true;
   262→    if (uni.light_pos.y < -0.20f) {
   263→        // Only cast shadow rays from surfaces above the threshold
   264→        do_shadow_check = (point.position.y >= -0.20f);
   265→    }
   266→
   267→    if (do_shadow_check) {
   268→        GPUIntersection occluder = closest_intersect_gpu(point.position,
   269→                                                         surface_light,
   270→                                                         triangles,
   271→                                                         triangle_count,
   272→                                                         1,  // light ray
   273→                                                         uni);
   274→
   275→        bool blocked = (occluder.triangle_index >= 0) &&
   276→                       (r > occluder.distance)        &&
   277→                       (result_dot > 0.0f)            &&
   278→                       (occluder.triangle_index != idx);
   279→
   280→        if (blocked) {
   281→            light_area = float3(0.0f);
   282→
   283→            // Soft shadow: 10 jittered samples
   284→            float3 soft = float3(0.0f);
   285→            for (int s = 0; s < 10; ++s) {
   286→                float jx = rand_float(seed) * 2.0f - 1.0f;
   287→                float jy = rand_float(seed) * 2.0f - 1.0f;
   288→                float jz = rand_float(seed) * 2.0f - 1.0f;
   289→
   290→                float3 jitter_dir = surface_light + float3(0.03f * jx,
   291→                                                           0.03f * jy,
   292→                                                           0.03f * jz);
   293→                if (shadow_intersect_gpu(point.position, jitter_dir,
   294→                                         idx, triangles, triangle_count)) {
   295→                    // fully in shadow — add nothing
   296→                } else {
   297→                    soft += triangles[idx].color.xyz;
   298→                }
   299→            }
   300→            light_area += soft / 10.0f;
   301→        }
   302→    }
   303→
   304→    return light_area;
   305→}
