   307→// ---------------------------------------------------------------------------
   308→// Kernel
   309→// ---------------------------------------------------------------------------
   310→kernel void raytracer_kernel(
   311→    uint3                          gid            [[thread_position_in_grid]],
   312→    constant GPUTriangle*          triangles      [[buffer(0)]],
   313→    constant RenderUniforms&       uni            [[buffer(1)]],
   314→    device   float4*               output_buffer  [[buffer(2)]])
   315→{
   316→    uint x          = gid.x;
   317→    uint y          = gid.y;
   318→    uint sample_idx = gid.z;
   319→
   320→    int sw = uni.screen_width;
   321→    int sh = uni.screen_height;
   322→
   323→    if (x >= (uint)sw || y >= (uint)sh || sample_idx >= 9u) return;
   324→
   325→    // --- Seed ---
   326→    uint seed = (x * 1000u + y) * 9u + sample_idx + 1u;
   327→
   328→    // --- Rotation matrix (yaw around Y axis) ---
   329→    // GLM mat3 col-major: col0=(cos,0,-sin), col1=(0,1,0), col2=(sin,0,cos)
   330→    // R*d = float3(cos*d.x + sin*d.z,  d.y,  -sin*d.x + cos*d.z)
   331→    float yaw     = uni.yaw;
   332→    float cos_yaw = cos(yaw);
   333→    float sin_yaw = sin(yaw);
   334→
   335→    // --- Primary ray focal point ---
   336→    float sw_f = float(sw);
   337→    float sh_f = float(sh);
   338→
   339→    float focal_x = (-0.5f + 0.5f / sw_f + float(x) / sw_f)
   340→                    * (uni.focal - uni.camera_pos.z) / uni.f;
   341→    float focal_y = (-0.5f + 0.5f / sh_f + float(y) / sh_f)
   342→                    * (uni.focal - uni.camera_pos.z) / uni.f;
   343→
   344→    // --- Anti-aliasing sub-sample grid (3×3, indices 0..8) ---
   345→    int a_idx = int(sample_idx) / 3;          // 0, 1, 2
   346→    int b_idx = int(sample_idx) % 3;          // 0, 1, 2
   347→    float a   = float(a_idx - 1) * 8.0f;     // -8, 0, 8
   348→    float b   = float(b_idx - 1) * 8.0f;     // -8, 0, 8
   349→
   350→    float x_ = b - b / 2.0f + b / 2.0f * rand_float(seed);
   351→    float y_ = a - a / 2.0f + a / 2.0f * rand_float(seed);
   352→
   353→    // --- Sub-pixel position ---
   354→    float3 sub_pixel = float3(
   355→        -0.5f + 0.5f / sw_f + (float(x) + x_) / sw_f,
   356→        -0.5f + 0.5f / sh_f + (float(y) + y_) / sh_f,
   357→        -2.0f
   358→    );
   359→
   360→    // --- Ray direction (before rotation) ---
   361→    float3 d_local = float3(focal_x - sub_pixel.x,
   362→                            focal_y - sub_pixel.y,
   363→                            uni.focal - sub_pixel.z);
   364→
   365→    // Apply Y-axis rotation: R*d
   366→    float3 d = float3(
   367→         cos_yaw * d_local.x + sin_yaw * d_local.z,
   368→         d_local.y,
   369→        -sin_yaw * d_local.x + cos_yaw * d_local.z
   370→    );
   371→
   372→    // --- Trace primary ray ---
   373→    GPUIntersection intersection = closest_intersect_gpu(
   374→        uni.camera_pos.xyz, d,
   375→        triangles, uni.triangle_count,
   376→        0, uni);
   377→
   378→    float3 pixel_colour = float3(0.0f);
   379→
   380→    if (intersection.triangle_index >= 0) {
   381→        float3 light_area = direct_light_gpu(intersection,
   382→                                             triangles,
   383→                                             uni.triangle_count,
   384→                                             uni,
   385→                                             seed);
   386→
   387→        if (intersection.is_mirror) {
   388→            // Mirror: also light the reflected surface and blend
   389→            int mirror_idx = intersection.triangle_index;
   390→
   391→            // Build a temporary intersection at the mirror hit to light it
   392→            // We already have the reflected colour in intersection.colour,
   393→            // but we need a GPUIntersection pointing at the reflected surface.
   394→            // Re-trace the reflected ray to get the proper surface intersection.
   395→            float3 reflect_dir = float3(-d.x, d.y, d.z);
   396→            GPUIntersection mirror_isec = mirror_intersect_gpu(
   397→                intersection.position, reflect_dir,
   398→                triangles, uni.triangle_count);
   399→
   400→            float3 mirror_shadow = float3(0.0f);
   401→            if (mirror_isec.triangle_index >= 0) {
   402→                mirror_shadow = direct_light_gpu(mirror_isec,
   403→                                                 triangles,
   404→                                                 uni.triangle_count,
   405→                                                 uni,
   406→                                                 seed);
   407→            }
   408→
   409→            light_area = 0.5f * (uni.indirect_light.xyz +
   410→                                 (light_area + mirror_shadow) / 2.0f);
   411→        } else {
   412→            light_area = 0.5f * (uni.indirect_light.xyz + light_area);
   413→        }
   414→
   415→        pixel_colour = light_area * intersection.colour;
   416→    }
   417→
   418→    // --- Write output ---
   419→    uint out_idx = (y * uint(sw) + x) * 9u + sample_idx;
   420→    output_buffer[out_idx] = float4(pixel_colour, 1.0f);
   421→}
