   371→    // Apply Y-axis rotation: R*d
   372→    float3 d = float3(
   373→         cos_yaw * d_local.x + sin_yaw * d_local.z,
   374→         d_local.y,
   375→        -sin_yaw * d_local.x + cos_yaw * d_local.z
   376→    );
   377→
   378→    // --- Trace primary ray ---
   379→    // Ray origin is sub_pixel (lens sample point at z=-2), NOT camera_pos (z=-3)
   380→    // This matches the CPU code: closest_intersection(sub_pixel, d, ...)
   381→    GPUIntersection intersection = closest_intersect_gpu(
   382→        sub_pixel, d,
   383→        triangles, uni.triangle_count,
   384→        0, uni);
   385→
   386→    float3 pixel_colour = float3(0.0f);
