   395→        if (intersection.is_mirror) {
   396→            // Mirror: also light the reflected surface and blend
   397→            int mirror_idx = intersection.triangle_index;
   398→
   399→            // Build a temporary intersection at the mirror hit to light it
   400→            // We already have the reflected colour in intersection.colour,
   401→            // but we need a GPUIntersection pointing at the reflected surface.
   402→            // Re-trace the reflected ray to get the proper surface intersection.
   403→            float3 reflect_dir = float3(-d.x, d.y, d.z);
   404→            GPUIntersection mirror_isec = mirror_intersect_gpu(
   405→                intersection.position, reflect_dir,
   406→                triangles, uni.triangle_count);
   407→
   408→            float3 mirror_shadow = float3(0.0f);
   409→            if (mirror_isec.triangle_index >= 0) {
   410→                mirror_shadow = direct_light_gpu(mirror_isec,
   411→                                                 triangles,
   412→                                                 uni.triangle_count,
   413→                                                 uni,
   414→                                                 seed);
   415→            }
   416→
   417→            light_area = 0.5f * (uni.indirect_light.xyz +
   418→                                 (light_area + mirror_shadow) / 2.0f);
   419→        } else {
   420→            light_area = 0.5f * (uni.indirect_light.xyz + light_area);
   421→        }
   422→
   423→        pixel_colour = light_area * intersection.colour;
   424→    }
   425→
   426→    // --- Write output ---
   427→    uint out_idx = (y * uint(sw) + x) * 9u + sample_idx;
   428→    output_buffer[out_idx] = float4(pixel_colour, 1.0f);
   429→}
