    64→                path = candidate;
    65→            }
    66→        }
    67→
    68→        if (!path) {
    69→            // Try directory containing the executable
    70→            NSString* execPath = [[NSProcessInfo processInfo] arguments][0];
    71→            NSString* execDir  = [execPath stringByDeletingLastPathComponent];
    72→            NSString* candidate = [execDir stringByAppendingPathComponent:@"raytracer.metallib"];
    73→            if ([[NSFileManager defaultManager] fileExistsAtPath:candidate]) {
    74→                path = candidate;
    75→            }
    76→        }
