   149→void MetalRenderer::uploadTriangles(const std::vector<Triangle>& tris)
   150→{
   151→    @autoreleasepool {
   152→        id<MTLDevice> device = (__bridge id<MTLDevice>)_device;
   153→        if (!device) return;
   154→
   155→        std::vector<GPUTriangle> gpuTris(tris.size());
   156→        for (size_t i = 0; i < tris.size(); ++i) {
   157→            gpuTris[i].v0     = toFloat4(tris[i].v0);
   158→            gpuTris[i].v1     = toFloat4(tris[i].v1);
   159→            gpuTris[i].v2     = toFloat4(tris[i].v2);
   160→            gpuTris[i].normal = toFloat4(tris[i].normal);
   161→            gpuTris[i].color  = toFloat4(tris[i].color);
   162→        }
   163→
   164→        NSUInteger bytes = gpuTris.size() * sizeof(GPUTriangle);
   165→        id<MTLBuffer> buf = [device newBufferWithBytes:gpuTris.data()
   166→                                                length:bytes
   167→                                               options:MTLResourceStorageModeShared];
   168→
   169→        // Release old buffer if present
   170→        if (_triangleBuffer) {
   171→            (void)(__bridge_transfer id<MTLBuffer>)_triangleBuffer;
   172→        }
   173→        _triangleBuffer = (__bridge_retained void*)buf;
   174→    }
   175→}
