   162→// ---------------------------------------------------------------------------
   163→// closest_intersect_gpu
   164→// ---------------------------------------------------------------------------
   165→inline GPUIntersection closest_intersect_gpu(float3 orig,
   166→                                             float3 dir,
   167→                                             constant GPUTriangle* triangles,
   168→                                             int triangle_count,
   169→                                             int light,              // 0 = normal, 1 = shadow ray
   170→                                             constant RenderUniforms& uni)
   171→{
   172→    GPUIntersection result;
   173→    result.distance       = 1e30f;
   174→    result.triangle_index = -1;
   175→    result.colour         = float3(0.0f);
   176→    result.is_mirror      = false;
   177→    result.position       = float3(0.0f);
   178→
   179→    // --- Front-plane test ---
   180→    int ignore = 1; // default: ignore front-plane (only render up to tri 9)
   181→    {
   182→        float t = 0.0f;
   183→        if (ray_triangle_intersect(orig, dir,
   184→                                   uni.front_v0.xyz,
   185→                                   uni.front_v1.xyz,
   186→                                   uni.front_v2.xyz,
   187→                                   t))
   188→        {
   189→            ignore = 0; // ray passed through the opening — see full scene
   190→        }
   191→    }
   192→
   193→    // --- Triangle loop ---
   194→    int loop_count = triangle_count;
   195→    if (ignore == 1 && light == 0) {
   196→        loop_count = min(10, triangle_count); // only first 10 triangles
   197→    }
   198→
   199→    for (int i = 0; i < loop_count; ++i) {
   200→        float t = 0.0f;
   201→        if (ray_triangle_intersect(orig, dir,
   202→                                   triangles[i].v0.xyz,
   203→                                   triangles[i].v1.xyz,
   204→                                   triangles[i].v2.xyz,
   205→                                   t))
   206→        {
   207→            if (t > 0.03f && t < result.distance) {
   208→                result.distance       = t;
   209→                result.triangle_index = i;
   210→                result.position       = orig + dir * t;
   211→            }
   212→        }
   213→    }
   214→
   215→    // --- Post-process hit ---
   216→    if (result.triangle_index >= 0) {
   217→        int idx = result.triangle_index;
   218→
   219→        if (idx == 4 || idx == 5) {
   220→            // Mirror surface: reflect and re-trace
   221→            float3 reflect_dir = float3(-dir.x, dir.y, dir.z);
   222→            GPUIntersection mirror_hit = mirror_intersect_gpu(result.position,
   223→                                                              reflect_dir,
   224→                                                              triangles,
   225→                                                              triangle_count);
   226→            result.colour    = mirror_hit.colour;
   227→            result.is_mirror = true;
   228→        } else {
   229→            result.colour    = triangles[idx].color.xyz;
   230→            result.is_mirror = false;
   231→        }
   232→    }
   233→
   234→    return result;
   235→}
