   240→inline float3 direct_light_gpu(GPUIntersection        point,
   241→                                constant GPUTriangle*  triangles,
   242→                                int                    triangle_count,
   243→                                constant RenderUniforms& uni,
   244→                                thread uint&           seed)
   245→{
   246→    int    idx           = point.triangle_index;
   247→    float3 surface_light = uni.light_pos.xyz - point.position;
   248→    float  r             = length(surface_light);
   249→
   250→    float  result_dot    = dot(surface_light, triangles[idx].normal.xyz);
   251→    float  area_divisor  = 4.0f * M_PI_F * r * r;
   252→
   253→    float3 light_area;
   254→    if (result_dot > 0.0f) {
   255→        light_area = (result_dot / area_divisor) * uni.light_colour.xyz;
   256→    } else {
   257→        light_area = float3(0.0f);
   258→    }
   259→
   260→    // --- Shadow branch ---
   261→    bool do_shadow_check = true;
   262→    if (uni.light_pos.y < -0.20f) {
   263→        // Only cast shadow rays from surfaces above the threshold
   264→        do_shadow_check = (point.position.y >= -0.20f);
   265→    }
   266→
   267→    if (do_shadow_check) {
   268→        GPUIntersection occluder = closest_intersect_gpu(point.position,
   269→                                                         surface_light,
   270→                                                         triangles,
   271→                                                         triangle_count,
   272→                                                         1,  // light ray
   273→                                                         uni);
   274→
   275→        // CPU checks: r > length(dis) where dis = t * surface_light
   276→        // → r > t * r → 1.0 > t
   277→        // i.e. occluder parameter t must be < 1.0 to be between surface and light
   278→        bool blocked = (occluder.triangle_index >= 0) &&
   279→                       (occluder.distance < 1.0f)     &&
   280→                       (result_dot > 0.0f)             &&
   281→                       (occluder.triangle_index != idx);
   282→
   283→        if (blocked) {
   284→            light_area = float3(0.0f);
   285→
   286→            // Soft shadow: 10 jittered samples
   287→            // Use occluder.triangle_index (not idx) to search around the occluder,
   288→            // matching CPU: shadow_intersection(point.position, direction, inter.triangle_index, ...)
   289→            int occluder_idx = occluder.triangle_index;
   290→            float3 soft = float3(0.0f);
   291→            for (int s = 0; s < 10; ++s) {
   292→                float jx = rand_float(seed) * 2.0f - 1.0f;
   293→                float jy = rand_float(seed) * 2.0f - 1.0f;
   294→                float jz = rand_float(seed) * 2.0f - 1.0f;
   295→
   296→                float3 jitter_dir = surface_light + float3(0.03f * jx,
   297→                                                           0.03f * jy,
   298→                                                           0.03f * jz);
   299→                if (shadow_intersect_gpu(point.position, jitter_dir,
   300→                                         occluder_idx, triangles, triangle_count)) {
   301→                    // fully in shadow — add nothing
   302→                } else {
   303→                    soft += triangles[idx].color.xyz;
   304→                }
   305→            }
   306→            light_area += soft / 10.0f;
   307→        }
   308→    }
   309→
   310→    return light_area;
   311→}
