   316→kernel void raytracer_kernel(
   317→    uint3                          gid            [[thread_position_in_grid]],
   318→    constant GPUTriangle*          triangles      [[buffer(0)]],
   319→    constant RenderUniforms&       uni            [[buffer(1)]],
   320→    device   float4*               output_buffer  [[buffer(2)]])
   321→{
   322→    uint x          = gid.x;
   323→    uint y          = gid.y;
   324→    uint sample_idx = gid.z;
   325→
   326→    int sw = uni.screen_width;
   327→    int sh = uni.screen_height;
   328→
   329→    if (x >= (uint)sw || y >= (uint)sh || sample_idx >= 9u) return;
