   336→    // R*d = float3(cos*d.x + sin*d.z,  d.y,  -sin*d.x + cos*d.z)
   337→    float yaw     = uni.yaw;
   338→    float cos_yaw = cos(yaw);
   339→    float sin_yaw = sin(yaw);
   340→
   341→    // --- Primary ray focal point ---
   342→    float sw_f = float(sw);
   343→    float sh_f = float(sh);
