     9→// Used to describe a triangular surface:
    10→class Triangle
    11→{
    12→public:
    13→	glm::vec3 v0;
    14→	glm::vec3 v1;
    15→	glm::vec3 v2;
    16→	glm::vec3 normal;
    17→	glm::vec3 color;
