     4→// ---------------------------------------------------------------------------
     5→// Constants
     6→// ---------------------------------------------------------------------------
     7→constant int   SCREEN_WIDTH  = 450;
     8→constant int   SCREEN_HEIGHT = 450;
     9→constant int   MAX_TRIANGLES = 30;
    10→
