    16→// ---------------------------------------------------------------------------
    17→// Data structures
    18→// ---------------------------------------------------------------------------
    19→struct GPUTriangle {
    20→    float4 v0;      // w unused
    21→    float4 v1;
    22→    float4 v2;
    23→    float4 normal;
    24→    float4 color;
    25→};
    26→
    27→struct RenderUniforms {
    28→    float4 camera_pos;
    29→    float4 light_pos;
    30→    float4 light_colour;
    31→    float4 indirect_light;
    32→    float4 front_v0;
    33→    float4 front_v1;
    34→    float4 front_v2;
    35→    float  focal;
    36→    float  f;
    37→    float  yaw;
    38→    int    triangle_count;
    39→    int    screen_width;
    40→    int    screen_height;
    41→    float  _pad[2];
    42→};
    43→
    44→struct GPUIntersection {
    45→    float3 position;
    46→    float  distance;
    47→    int    triangle_index;
    48→    float3 colour;
    49→    bool   is_mirror;
    50→};
    51→
    52→// ---------------------------------------------------------------------------
    53→// LCG random number generator
    54→// ---------------------------------------------------------------------------
    55→inline uint lcg_rand(thread uint& seed) {
    56→    seed = seed * 1664525u + 1013904223u;
    57→    return seed;
    58→}
    59→
    60→inline float rand_float(thread uint& seed) {
    61→    return float(lcg_rand(seed)) / 4294967295.0f;
    62→}
    63→
    64→// ---------------------------------------------------------------------------
    65→// Möller–Trumbore ray-triangle intersection
    66→// Returns true and writes t if the ray hits the triangle.
    67→// ---------------------------------------------------------------------------
    68→inline bool ray_triangle_intersect(float3 orig,
    69→                                   float3 dir,
    70→                                   float3 v0,
    71→                                   float3 v1,
    72→                                   float3 v2,
    73→                                   thread float& t)
    74→{
    75→    const float epsilon = 1e-6f;
    76→
    77→    float3 e1 = v1 - v0;
    78→    float3 e2 = v2 - v0;
    79→
    80→    float3 pvec = cross(dir, e2);
    81→    float  det  = dot(e1, pvec);
    82→
    83→    if (abs(det) < epsilon) return false;
    84→
    85→    float  invDet = 1.0f / det;
    86→    float3 tvec   = orig - v0;
    87→
    88→    float u = dot(tvec, pvec) * invDet;
    89→    if (u < 0.0f || u > 1.0f) return false;
    90→
    91→    float3 qvec = cross(tvec, e1);
    92→    float  v    = dot(dir, qvec) * invDet;
    93→    if (v < 0.0f || u + v > 1.0f) return false;
    94→
    95→    t = dot(e2, qvec) * invDet;
    96→    return t > 0.0f;
    97→}
    98→
    99→// ---------------------------------------------------------------------------
   100→// mirror_intersect_gpu
   101→// Scans all triangles and returns the closest hit (t > 0.03).
   102→// ---------------------------------------------------------------------------
   103→inline GPUIntersection mirror_intersect_gpu(float3 orig,
   104→                                            float3 dir,
   105→                                            constant GPUTriangle* triangles,
   106→                                            int triangle_count)
   107→{
   108→    GPUIntersection result;
   109→    result.distance       = 1e30f;
   110→    result.triangle_index = -1;
   111→    result.colour         = float3(0.0f);
   112→    result.is_mirror      = false;
   113→    result.position       = float3(0.0f);
   114→
   115→    for (int i = 0; i < triangle_count; ++i) {
   116→        float t = 0.0f;
   117→        if (ray_triangle_intersect(orig, dir,
   118→                                   triangles[i].v0.xyz,
   119→                                   triangles[i].v1.xyz,
   120→                                   triangles[i].v2.xyz,
   121→                                   t))
   122→        {
   123→            if (t > 0.03f && t < result.distance) {
   124→                result.distance       = t;
   125→                result.triangle_index = i;
   126→                result.position       = orig + dir * t;
   127→                result.colour         = triangles[i].color.xyz;
   128→            }
   129→        }
   130→    }
   131→
   132→    return result;
   133→}
   134→
   135→// ---------------------------------------------------------------------------
   136→// shadow_intersect_gpu
   137→// Tests a narrow band of triangles around `id` for any occlusion.
   138→// ---------------------------------------------------------------------------
   139→inline bool shadow_intersect_gpu(float3 orig,
   140→                                 float3 dir,
   141→                                 int    id,
   142→                                 constant GPUTriangle* triangles,
   143→                                 int triangle_count)
   144→{
   145→    int lo = max(0,              id - 2);
   146→    int hi = min(triangle_count, id + 3);
   147→
   148→    for (int i = lo; i < hi; ++i) {
   149→        float t = 0.0f;
   150→        if (ray_triangle_intersect(orig, dir,
   151→                                   triangles[i].v0.xyz,
   152→                                   triangles[i].v1.xyz,
   153→                                   triangles[i].v2.xyz,
   154→                                   t))
   155→        {
   156→            if (t > 0.0f) return true;
   157→        }
   158→    }
   159→    return false;
   160→}
   161→
   162→// ---------------------------------------------------------------------------
   163→// closest_intersect_gpu
   164→// ---------------------------------------------------------------------------
   165→inline GPUIntersection closest_intersect_gpu(float3 orig,
   166→                                             float3 dir,
   167→                                             constant GPUTriangle* triangles,
   168→                                             int triangle_count,
   169→                                             int light,              // 0 = normal, 1 = shadow ray
   170→                                             constant RenderUniforms& uni)
   171→{
   172→    GPUIntersection result;
   173→    result.distance       = 1e30f;
   174→    result.triangle_index = -1;
   175→    result.colour         = float3(0.0f);
   176→    result.is_mirror      = false;
   177→    result.position       = float3(0.0f);
   178→
   179→    // --- Front-plane test ---
   180→    int ignore = 1; // default: ignore front-plane (only render up to tri 9)
   181→    {
   182→        float t = 0.0f;
   183→        if (ray_triangle_intersect(orig, dir,
   184→                                   uni.front_v0.xyz,
   185→                                   uni.front_v1.xyz,
   186→                                   uni.front_v2.xyz,
   187→                                   t))
   188→        {
   189→            ignore = 0; // ray passed through the opening — see full scene
   190→        }
   191→    }
   192→
   193→    // --- Triangle loop ---
   194→    int loop_count = triangle_count;
   195→    if (ignore == 1 && light == 0) {
   196→        loop_count = min(10, triangle_count); // only first 10 triangles
   197→    }
   198→
   199→    for (int i = 0; i < loop_count; ++i) {
   200→        float t = 0.0f;
   201→        if (ray_triangle_intersect(orig, dir,
   202→                                   triangles[i].v0.xyz,
   203→                                   triangles[i].v1.xyz,
   204→                                   triangles[i].v2.xyz,
   205→                                   t))
   206→        {
   207→            if (t > 0.03f && t < result.distance) {
   208→                result.distance       = t;
   209→                result.triangle_index = i;
   210→                result.position       = orig + dir * t;
   211→            }
   212→        }
   213→    }
   214→
   215→    // --- Post-process hit ---
   216→    if (result.triangle_index >= 0) {
   217→        int idx = result.triangle_index;
   218→
   219→        if (idx == 4 || idx == 5) {
   220→            // Mirror surface: reflect and re-trace
   221→            float3 reflect_dir = float3(-dir.x, dir.y, dir.z);
   222→            GPUIntersection mirror_hit = mirror_intersect_gpu(result.position,
   223→                                                              reflect_dir,
   224→                                                              triangles,
   225→                                                              triangle_count);
   226→            result.colour    = mirror_hit.colour;
   227→            result.is_mirror = true;
   228→        } else {
   229→            result.colour    = triangles[idx].color.xyz;
   230→            result.is_mirror = false;
   231→        }
   232→    }
   233→
   234→    return result;
   235→}
   236→
   237→// ---------------------------------------------------------------------------
   238→// direct_light_gpu
   239→// ---------------------------------------------------------------------------
   240→inline float3 direct_light_gpu(GPUIntersection        point,
   241→                                constant GPUTriangle*  triangles,
   242→                                int                    triangle_count,
   243→                                constant RenderUniforms& uni,
   244→                                thread uint&           seed)
   245→{
   246→    int    idx           = point.triangle_index;
   247→    float3 surface_light = uni.light_pos.xyz - point.position;
   248→    float  r             = length(surface_light);
   249→
   250→    float  result_dot    = dot(surface_light, triangles[idx].normal.xyz);
   251→    float  area_divisor  = 4.0f * M_PI_F * r * r;
   252→
   253→    float3 light_area;
   254→    if (result_dot > 0.0f) {
   255→        light_area = (result_dot / area_divisor) * uni.light_colour.xyz;
   256→    } else {
   257→        light_area = float3(0.0f);
   258→    }
   259→
   260→    // --- Shadow branch ---
   261→    bool do_shadow_check = true;
   262→    if (uni.light_pos.y < -0.20f) {
   263→        // Only cast shadow rays from surfaces above the threshold
   264→        do_shadow_check = (point.position.y >= -0.20f);
   265→    }
   266→
   267→    if (do_shadow_check) {
   268→        GPUIntersection occluder = closest_intersect_gpu(point.position,
   269→                                                         surface_light,
   270→                                                         triangles,
   271→                                                         triangle_count,
   272→                                                         1,  // light ray
   273→                                                         uni);
   274→
   275→        // CPU checks: r > length(dis) where dis = t * surface_light
   276→        // → r > t * r → 1.0 > t
   277→        // i.e. occluder parameter t must be < 1.0 to be between surface and light
   278→        bool blocked = (occluder.triangle_index >= 0) &&
   279→                       (occluder.distance < 1.0f)     &&
   280→                       (result_dot > 0.0f)             &&
   281→                       (occluder.triangle_index != idx);
   282→
   283→        if (blocked) {
   284→            light_area = float3(0.0f);
   285→
   286→            // Soft shadow: 10 jittered samples
   287→            // Use occluder.triangle_index (not idx) to search around the occluder,
   288→            // matching CPU: shadow_intersection(point.position, direction, inter.triangle_index, ...)
   289→            int occluder_idx = occluder.triangle_index;
   290→            float3 soft = float3(0.0f);
   291→            for (int s = 0; s < 10; ++s) {
   292→                float jx = rand_float(seed) * 2.0f - 1.0f;
   293→                float jy = rand_float(seed) * 2.0f - 1.0f;
   294→                float jz = rand_float(seed) * 2.0f - 1.0f;
   295→
   296→                float3 jitter_dir = surface_light + float3(0.03f * jx,
   297→                                                           0.03f * jy,
   298→                                                           0.03f * jz);
   299→                if (shadow_intersect_gpu(point.position, jitter_dir,
   300→                                         occluder_idx, triangles, triangle_count)) {
   301→                    // fully in shadow — add nothing
   302→                } else {
   303→                    soft += triangles[idx].color.xyz;
   304→                }
   305→            }
