   316→kernel void raytracer_kernel(
   317→    uint3                          gid            [[thread_position_in_grid]],
   318→    constant GPUTriangle*          triangles      [[buffer(0)]],
   319→    constant RenderUniforms&       uni            [[buffer(1)]],
   320→    device   float4*               output_buffer  [[buffer(2)]])
   321→{
   322→    uint x          = gid.x;
   323→    uint y          = gid.y;
   324→    uint sample_idx = gid.z;
   325→
   326→    int sw = uni.screen_width;
   327→    int sh = uni.screen_height;
   328→
   329→    if (x >= (uint)sw || y >= (uint)sh || sample_idx >= 9u) return;
   330→
   331→    // --- Seed ---
   332→    uint seed = (x * 1000u + y) * 9u + sample_idx + 1u;
   333→
   334→    // --- Rotation matrix (yaw around Y axis) ---
   335→    // GLM mat3 col-major: col0=(cos,0,-sin), col1=(0,1,0), col2=(sin,0,cos)
   336→    // R*d = float3(cos*d.x + sin*d.z,  d.y,  -sin*d.x + cos*d.z)
   337→    float yaw     = uni.yaw;
   338→    float cos_yaw = cos(yaw);
   339→    float sin_yaw = sin(yaw);
   340→
   341→    // --- Primary ray focal point ---
   342→    float sw_f = float(sw);
   343→    float sh_f = float(sh);
   344→
   345→    float focal_x = (-0.5f + 0.5f / sw_f + float(x) / sw_f)
   346→                    * (uni.focal - uni.camera_pos.z) / uni.f;
   347→    float focal_y = (-0.5f + 0.5f / sh_f + float(y) / sh_f)
   348→                    * (uni.focal - uni.camera_pos.z) / uni.f;
   349→
   350→    // --- Anti-aliasing sub-sample grid (3×3, stratified jitter) ---
   351→    // Divide [-8, 8] into 3 equal strata of width 16/3 each.
   352→    // Each sample falls uniformly within its stratum — no gaps, no overlap.
   353→    // Total spread stays ±8 pixels so depth-of-field effect is unchanged.
   354→    int a_idx = int(sample_idx) / 3;   // 0, 1, 2
   355→    int b_idx = int(sample_idx) % 3;   // 0, 1, 2
   356→
   357→    float x_ = -8.0f + (float(b_idx) + rand_float(seed)) * (16.0f / 3.0f);
   358→    float y_ = -8.0f + (float(a_idx) + rand_float(seed)) * (16.0f / 3.0f);
   359→
   360→    // --- Sub-pixel position ---
   361→    float3 sub_pixel = float3(
   362→        -0.5f + 0.5f / sw_f + (float(x) + x_) / sw_f,
   363→        -0.5f + 0.5f / sh_f + (float(y) + y_) / sh_f,
   364→        -2.0f
   365→    );
   366→
   367→    // --- Ray direction (before rotation) ---
   368→    float3 d_local = float3(focal_x - sub_pixel.x,
   369→                            focal_y - sub_pixel.y,
   370→                            uni.focal - sub_pixel.z);
   371→
   372→    // Apply Y-axis rotation: R*d
   373→    float3 d = float3(
   374→         cos_yaw * d_local.x + sin_yaw * d_local.z,
   375→         d_local.y,
   376→        -sin_yaw * d_local.x + cos_yaw * d_local.z
   377→    );
   378→
   379→    // --- Trace primary ray ---
   380→    // Ray origin is sub_pixel (lens sample point at z=-2), NOT camera_pos (z=-3)
   381→    // This matches the CPU code: closest_intersection(sub_pixel, d, ...)
   382→    GPUIntersection intersection = closest_intersect_gpu(
   383→        sub_pixel, d,
   384→        triangles, uni.triangle_count,
   385→        0, uni);
   386→
   387→    float3 pixel_colour = float3(0.0f);
   388→
   389→    if (intersection.triangle_index >= 0) {
   390→        float3 light_area = direct_light_gpu(intersection,
   391→                                             triangles,
   392→                                             uni.triangle_count,
   393→                                             uni,
   394→                                             seed);
   395→
   396→        if (intersection.is_mirror) {
   397→            // Mirror: also light the reflected surface and blend
   398→            int mirror_idx = intersection.triangle_index;
   399→
   400→            // Build a temporary intersection at the mirror hit to light it
   401→            // We already have the reflected colour in intersection.colour,
   402→            // but we need a GPUIntersection pointing at the reflected surface.
   403→            // Re-trace the reflected ray to get the proper surface intersection.
   404→            float3 reflect_dir = float3(-d.x, d.y, d.z);
   405→            GPUIntersection mirror_isec = mirror_intersect_gpu(
   406→                intersection.position, reflect_dir,
   407→                triangles, uni.triangle_count);
   408→
   409→            float3 mirror_shadow = float3(0.0f);
   410→            if (mirror_isec.triangle_index >= 0) {
   411→                mirror_shadow = direct_light_gpu(mirror_isec,
   412→                                                 triangles,
   413→                                                 uni.triangle_count,
   414→                                                 uni,
   415→                                                 seed);
   416→            }
   417→
   418→            light_area = 0.5f * (uni.indirect_light.xyz +
   419→                                 (light_area + mirror_shadow) / 2.0f);
