   424→        pixel_colour = light_area * intersection.colour;
   425→    }
   426→
   427→    // --- Write output ---
   428→    uint out_idx = (y * uint(sw) + x) * 9u + sample_idx;
   429→    output_buffer[out_idx] = float4(pixel_colour, 1.0f);
   430→}
