   222→// ---------------------------------------------------------------------------
   223→// direct_light_gpu
   224→// ---------------------------------------------------------------------------
   225→inline float3 direct_light_gpu(GPUIntersection        point,
   226→                                constant GPUTriangle*  triangles,
   227→                                int                    triangle_count,
   228→                                constant RenderUniforms& uni,
   229→                                thread uint&           seed)
   230→{
   231→    int    idx           = point.triangle_index;
   232→    float3 surface_light = uni.light_pos.xyz - point.position;
   233→    float  r             = length(surface_light);
   234→
   235→    float  result_dot    = dot(surface_light, triangles[idx].normal.xyz);
   236→    float  area_divisor  = 4.0f * M_PI_F * r * r;
   237→
   238→    float3 light_area;
   239→    if (result_dot > 0.0f) {
   240→        light_area = (result_dot / area_divisor) * uni.light_colour.xyz;
   241→    } else {
   242→        light_area = float3(0.0f);
   243→    }
   244→
   245→    // --- Shadow branch ---
   246→    bool do_shadow_check = true;
   247→    if (uni.light_pos.y < -0.20f) {
   248→        // Only cast shadow rays from surfaces above the threshold
   249→        do_shadow_check = (point.position.y >= -0.20f);
   250→    }
   251→
   252→    if (do_shadow_check) {
   253→        GPUIntersection occluder = closest_intersect_gpu(point.position,
   254→                                                         surface_light,
   255→                                                         triangles,
   256→                                                         triangle_count,
   257→                                                         1,  // light ray
   258→                                                         uni);
   259→
   260→        // CPU checks: r > length(dis) where dis = t * surface_light
   261→        // → r > t * r → 1.0 > t
   262→        // i.e. occluder parameter t must be < 1.0 to be between surface and light
   263→        bool blocked = (occluder.triangle_index >= 0) &&
   264→                       (occluder.distance < 1.0f)     &&
   265→                       (result_dot > 0.0f)             &&
   266→                       (occluder.triangle_index != idx);
   267→
   268→        if (blocked) {
   269→            light_area = float3(0.0f);
   270→
   271→            // Soft shadow: 10 jittered samples
   272→            // Use occluder.triangle_index (not idx) to search around the occluder,
   273→            // matching CPU: shadow_intersection(point.position, direction, inter.triangle_index, ...)
   274→            int occluder_idx = occluder.triangle_index;
   275→            float3 soft = float3(0.0f);
   276→            for (int s = 0; s < 10; ++s) {
   277→                float jx = rand_float(seed) * 2.0f - 1.0f;
   278→                float jy = rand_float(seed) * 2.0f - 1.0f;
   279→                float jz = rand_float(seed) * 2.0f - 1.0f;
   280→
   281→                float3 jitter_dir = surface_light + float3(0.03f * jx,
   282→                                                           0.03f * jy,
   283→                                                           0.03f * jz);
   284→                if (shadow_intersect_gpu(point.position, jitter_dir,
   285→                                         occluder_idx, triangles, triangle_count)) {
   286→                    // fully in shadow — add nothing
   287→                } else {
   288→                    soft += triangles[idx].color.xyz;
   289→                }
   290→            }
   291→            light_area += soft / 10.0f;
   292→        }
   293→    }
   294→
   295→    return light_area;
   296→}
