    71→inline bool RayTriangleIntersection(const vec3& orig,
    72→                                    const vec3& dir,
    73→                                    const vec3& v0,
    74→                                    const vec3& v1,
    75→                                    const vec3& v2,
    76→                                    float& t,
    77→                                    float& u,
    78→                                    float& v)
    79→{
    80→    const float EPSILON = 1e-6f;
    81→    vec3 e1 = v1 - v0;
    82→    vec3 e2 = v2 - v0;
    83→    vec3 pvec = glm::cross(dir, e2);
    84→    float det = glm::dot(e1, pvec);
    85→    if (fabs(det) < EPSILON)
    86→        return false;
    87→
    88→    float invDet = 1.0f / det;
    89→    vec3 tvec = orig - v0;
    90→    u = glm::dot(tvec, pvec) * invDet;
    91→    if (u < 0.0f || u > 1.0f)
    92→        return false;
    93→
    94→    vec3 qvec = glm::cross(tvec, e1);
    95→    v = glm::dot(dir, qvec) * invDet;
    96→    if (v < 0.0f || u + v > 1.0f)
    97→        return false;
    98→
    99→    t = glm::dot(e2, qvec) * invDet;
   100→    return t > 0.0f;
   101→}
